CREATE TYPE "CommercialDocumentType" AS ENUM ('PROPOSAL','QUOTATION','CONTRACT');
CREATE TYPE "CommercialDocumentStatus" AS ENUM ('DRAFT','SENT','VIEWED','ACCEPTED','REJECTED','EXPIRED','CANCELLED');
CREATE TYPE "CommercialApprovalAction" AS ENUM ('CREATED','UPDATED','SENT','VIEWED','ACCEPTED','REJECTED','CANCELLED');
CREATE TABLE "commercial_documents" ("id" TEXT NOT NULL,"type" "CommercialDocumentType" NOT NULL,"documentNumber" TEXT NOT NULL,"title" TEXT NOT NULL,"status" "CommercialDocumentStatus" NOT NULL DEFAULT 'DRAFT',"currency" TEXT NOT NULL DEFAULT 'INR',"issueDate" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"validUntil" TIMESTAMP(3),"startDate" TIMESTAMP(3),"endDate" TIMESTAMP(3),"scope" TEXT,"terms" TEXT,"notes" TEXT,"subtotal" DOUBLE PRECISION NOT NULL DEFAULT 0,"discountAmount" DOUBLE PRECISION NOT NULL DEFAULT 0,"taxPercent" DOUBLE PRECISION NOT NULL DEFAULT 0,"taxAmount" DOUBLE PRECISION NOT NULL DEFAULT 0,"totalAmount" DOUBLE PRECISION NOT NULL DEFAULT 0,"publicToken" TEXT NOT NULL,"sentAt" TIMESTAMP(3),"viewedAt" TIMESTAMP(3),"acceptedAt" TIMESTAMP(3),"rejectedAt" TIMESTAMP(3),"acceptedByName" TEXT,"acceptedByEmail" TEXT,"clientId" TEXT,"leadId" TEXT,"createdById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "commercial_documents_pkey" PRIMARY KEY ("id"));
CREATE TABLE "commercial_document_items" ("id" TEXT NOT NULL,"documentId" TEXT NOT NULL,"description" TEXT NOT NULL,"quantity" DOUBLE PRECISION NOT NULL DEFAULT 1,"unitPrice" DOUBLE PRECISION NOT NULL,"amount" DOUBLE PRECISION NOT NULL,"sortOrder" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "commercial_document_items_pkey" PRIMARY KEY ("id"));
CREATE TABLE "commercial_approval_logs" ("id" TEXT NOT NULL,"documentId" TEXT NOT NULL,"action" "CommercialApprovalAction" NOT NULL,"actorName" TEXT,"actorEmail" TEXT,"comments" TEXT,"ipAddress" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "commercial_approval_logs_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "commercial_documents_documentNumber_key" ON "commercial_documents"("documentNumber");
CREATE UNIQUE INDEX "commercial_documents_publicToken_key" ON "commercial_documents"("publicToken");
CREATE INDEX "commercial_documents_type_status_idx" ON "commercial_documents"("type","status");
ALTER TABLE "commercial_documents" ADD CONSTRAINT "commercial_documents_clientId_fkey" FOREIGN KEY ("clientId") REFERENCES "clients"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "commercial_documents" ADD CONSTRAINT "commercial_documents_leadId_fkey" FOREIGN KEY ("leadId") REFERENCES "leads"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "commercial_documents" ADD CONSTRAINT "commercial_documents_createdById_fkey" FOREIGN KEY ("createdById") REFERENCES "users"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "commercial_document_items" ADD CONSTRAINT "commercial_document_items_documentId_fkey" FOREIGN KEY ("documentId") REFERENCES "commercial_documents"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "commercial_approval_logs" ADD CONSTRAINT "commercial_approval_logs_documentId_fkey" FOREIGN KEY ("documentId") REFERENCES "commercial_documents"("id") ON DELETE CASCADE ON UPDATE CASCADE;
